import React from 'react';
import {
  Container,
  Grid,
  Card,
  CardContent,
  CardMedia,
  Typography,
  Box,
  Button,
  Chip,
} from '@mui/material';
import { motion } from 'framer-motion';
import OpenInNewIcon from '@mui/icons-material/OpenInNew';

const MotionCard = motion(Card);

const Blog = () => {
  const blogPosts = [
    {
      title: 'Getting Started with React Hooks',
      excerpt: 'A comprehensive guide to understanding and implementing React Hooks in your applications.',
      image: '/blog/react-hooks.jpg',
      date: 'March 15, 2024',
      readTime: '5 min read',
      category: 'Web Development',
      link: 'https://yourblog.com/react-hooks',
      tags: ['React', 'JavaScript', 'Web Development'],
    },
    {
      title: 'Building RESTful APIs with Node.js',
      excerpt: 'Learn how to create scalable and maintainable REST APIs using Node.js and Express.',
      image: '/blog/node-api.jpg',
      date: 'March 10, 2024',
      readTime: '8 min read',
      category: 'Backend Development',
      link: 'https://yourblog.com/node-rest-api',
      tags: ['Node.js', 'Express', 'API Design'],
    },
    // Add more blog posts as needed
  ];

  return (
    <Container maxWidth="lg" sx={{ py: 8 }}>
      <Typography variant="h2" component="h1" gutterBottom align="center">
        Blog
      </Typography>
      <Typography
        variant="h5"
        color="text.secondary"
        paragraph
        align="center"
        sx={{ mb: 6 }}
      >
        Latest articles and insights
      </Typography>

      <Grid container spacing={4}>
        {blogPosts.map((post, index) => (
          <Grid item xs={12} md={6} key={index}>
            <MotionCard
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              sx={{
                height: '100%',
                display: 'flex',
                flexDirection: 'column',
                transition: 'transform 0.2s',
                '&:hover': {
                  transform: 'translateY(-8px)',
                },
              }}
            >
              <CardMedia
                component="img"
                height="200"
                image={post.image}
                alt={post.title}
              />
              <CardContent sx={{ flexGrow: 1 }}>
                <Box sx={{ mb: 2 }}>
                  <Chip
                    label={post.category}
                    size="small"
                    color="primary"
                    sx={{ mb: 1 }}
                  />
                  <Typography
                    variant="caption"
                    color="text.secondary"
                    sx={{ ml: 1 }}
                  >
                    {post.date} • {post.readTime}
                  </Typography>
                </Box>

                <Typography variant="h5" component="h2" gutterBottom>
                  {post.title}
                </Typography>
                <Typography
                  variant="body1"
                  color="text.secondary"
                  paragraph
                >
                  {post.excerpt}
                </Typography>

                <Box sx={{ mt: 2, mb: 2 }}>
                  {post.tags.map((tag) => (
                    <Chip
                      key={tag}
                      label={tag}
                      size="small"
                      sx={{ mr: 1, mb: 1 }}
                    />
                  ))}
                </Box>

                <Button
                  variant="outlined"
                  endIcon={<OpenInNewIcon />}
                  href={post.link}
                  target="_blank"
                >
                  Read More
                </Button>
              </CardContent>
            </MotionCard>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
};

export default Blog;
